member.example:
Bind the content type of a TMP_InputField using a serialized binder field — the target is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private InputFieldContentTypeBinder _contentType;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public TMP_InputField.ContentType _contentType;
    }


Bind the content type of a TMP_InputField by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField] private TMP_InputField _inputField;
        
        private InputFieldContentTypeBinder ContentType =>
            new(_inputField);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public TMP_InputField.ContentType _contentType;
    }

Switch the content type of a TMP_InputField between two values using a serialized binder field — the target is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private InputFieldContentTypeSwitcherBinder _isEmailContent;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _isEmailContent;
    }


Switch the content type of a TMP_InputField between two values by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField] private TMP_InputField _inputField;
        
        private InputFieldContentTypeSwitcherBinder IsEmailContent => new(
            _inputField,
            TMP_InputField.ContentType.EmailAddress,
            TMP_InputField.ContentType.Standard);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _isEmailContent;
    }
